/**
 * Extrae el bloque HTML de la respuesta del agente.
 * Maneja: array [{ output: "..." }], markdown con bloques ```html.
 */

const getRaw = (data) => {
  if (Array.isArray(data) && data.length > 0) {
    const first = data[0];
    return String(
      first.output ??
      first.html ??
      first.response ??
      first.text ??
      first.result ??
      first.message?.content?.[0]?.text ??
      first.content?.[0]?.text ??
      ''
    ).trim();
  }
  const obj = data && typeof data === 'object' ? data : {};
  return String(
    obj.output ??
    obj.html ??
    obj.response ??
    obj.text ??
    obj.result ??
    obj.message?.content?.[0]?.text ??
    obj.content?.[0]?.text ??
    ''
  ).trim();
};

const raw = getRaw($input?.item?.json ?? $json ?? $input ?? {});

let html = '';
const htmlBlockMatch = raw.match(/```html\s*([\s\S]*?)```/i);
if (htmlBlockMatch) {
  html = htmlBlockMatch[1].trim();
} else {
  html = raw
    .replace(/^[\s\S]*?```html\s*/i, '')
    .replace(/\s*```[\s\S]*$/i, '')
    .trim();
}

const looksLikeHtml = /<(html|body|table|div|tr|td|img|a|p)\b/i.test(html);
if (!looksLikeHtml) {
  throw new Error('AI Agent no devolvió HTML utilizable. Verificar logs del agente.');
}

// Minificar: quitar saltos de línea y espacios múltiples entre tags
html = html
  .replace(/>\s+</g, '><')
  .replace(/\s+/g, ' ')
  .trim();

return [{ json: { html, source: 'agent_responsive_skill' } }];
